    SseSerializer serializer,
  ) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_list_waypoint(self.optimalSequence, serializer);
    sse_encode_f_64(self.totalDistanceKm, serializer);
  }

  @protected
  void sse_encode_rust_place_result(
    RustPlaceResult self,
    SseSerializer serializer,
  ) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.id, serializer);
    sse_encode_String(self.name, serializer);
    sse_encode_String(self.fullAddress, serializer);
    sse_encode_f_64(self.latitude, serializer);
    sse_encode_f_64(self.longitude, serializer);
    sse_encode_opt_String(self.category, serializer);
    sse_encode_opt_box_autoadd_f_64(self.distanceKm, serializer);
  }

  @protected
  void sse_encode_rust_route_result(
    RustRouteResult self,
    SseSerializer serializer,
  ) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_list_coord_pair(self.polylinePoints, serializer);
    sse_encode_f_64(self.distanceKm, serializer);
    sse_encode_f_64(self.durationSeconds, serializer);
    sse_encode_String(self.summary, serializer);
  }

  @protected
  void sse_encode_u_8(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putUint8(self);
  }

